import base64
import json
from odoo import http
from odoo.http import request


class ProjectDailyController(http.Controller):

    @http.route('/project/daily/form', type='http', auth='user', website=True)
    def daily_form(self, **kw):
        projects = request.env['project.project'].search([])
        employees = request.env['hr.employee'].search([])

        values = {
            'projects': projects,
            'employees': employees,
            'current_employee': request.env.user.employee_id,
        }
        return request.render('project_dailys.daily_form_template', values)

    def _time_to_float(self, time_str):
        """Convert HH:MM time string to float (e.g., '08:30' -> 8.5)"""
        if not time_str:
            return 0.0
        try:
            hours, minutes = time_str.split(':')
            return int(hours) + int(minutes) / 60.0
        except:
            return 0.0

    @http.route('/project/daily/submit', type='json', auth='user', methods=['POST'])
    def daily_submit(self, **post):
        try:
            project_id = int(post.get('project_id'))
            employee_id = int(post.get('employee_id'))
            date = post.get('date')
            description = post.get('description')
            materials_used = post.get('materials_used', '')
            issues = post.get('issues', '')
            location = post.get('location', '')
            weather = post.get('weather', '')

            # New time tracking fields
            time_in = self._time_to_float(post.get('time_in', ''))
            time_out = self._time_to_float(post.get('time_out', ''))
            lunch_time = float(post.get('lunch_time', 0))
            techs_on_site = int(post.get('techs_on_site', 1))

            images = post.get('images', [])
            receipts = post.get('receipts', [])
            timesheets = post.get('timesheets', [])

            daily = request.env['project.daily'].create({
                'project_id': project_id,
                'employee_id': employee_id,
                'date': date,
                'description': description,
                'time_in': time_in,
                'time_out': time_out,
                'lunch_time': lunch_time,
                'techs_on_site': techs_on_site,
                'materials_used': materials_used,
                'issues': issues,
                'location': location,
                'weather': weather,
            })

            # Process photos
            for idx, img_data in enumerate(images):
                if img_data and img_data.get('data'):
                    image_content = img_data['data'].split(',')[1] if ',' in img_data['data'] else img_data['data']
                    request.env['project.daily.image'].create({
                        'daily_id': daily.id,
                        'name': img_data.get('name', f'Photo {idx + 1}'),
                        'image': image_content,
                        'sequence': idx + 1,
                        'image_type': 'photo',
                    })

            # Process receipts
            for idx, receipt_data in enumerate(receipts):
                if receipt_data and receipt_data.get('data'):
                    receipt_content = receipt_data['data'].split(',')[1] if ',' in receipt_data['data'] else receipt_data['data']
                    request.env['project.daily.image'].create({
                        'daily_id': daily.id,
                        'name': receipt_data.get('name', f'Receipt {idx + 1}'),
                        'image': receipt_content,
                        'sequence': idx + 1,
                        'image_type': 'receipt',
                    })

            # Process timesheets
            for idx, ts_data in enumerate(timesheets):
                if ts_data and ts_data.get('data'):
                    ts_content = ts_data['data'].split(',')[1] if ',' in ts_data['data'] else ts_data['data']
                    # Create ir.attachment
                    attachment = request.env['ir.attachment'].create({
                        'name': ts_data.get('name', f'Timesheet {idx + 1}'),
                        'datas': ts_content,
                        'res_model': 'project.daily',
                        'res_id': daily.id,
                    })
                    # Create project.daily.attachment record
                    request.env['project.daily.attachment'].create({
                        'daily_id': daily.id,
                        'name': ts_data.get('name', f'Timesheet {idx + 1}'),
                        'attachment_id': attachment.id,
                    })

            return {
                'success': True,
                'message': 'Daily report submitted successfully!',
                'daily_id': daily.id,
                'daily_name': daily.name,
            }
        except Exception as e:
            import traceback
            import logging
            _logger = logging.getLogger(__name__)
            _logger.error('Error submitting daily report: %s\n%s', str(e), traceback.format_exc())
            return {
                'success': False,
                'message': str(e),
            }

    @http.route('/project/daily/get_projects', type='json', auth='user')
    def get_projects(self):
        projects = request.env['project.project'].search([])
        return [{
            'id': p.id,
            'name': p.name,
            'stage': p.stage_id.name if hasattr(p, 'stage_id') and p.stage_id else '',
        } for p in projects]

