console.log('[DailyForm] Script file is being executed');

function initDailyForm() {
    console.log('[DailyForm] Initializing form...');

    const form = document.getElementById('dailyReportForm');
    if (!form) {
        console.error('[DailyForm] Form element not found! ID: dailyReportForm');
        return;
    }

    // Check if already initialized
    if (form.dataset.initialized === 'true') {
        console.warn('[DailyForm] Form already initialized, skipping...');
        return;
    }

    console.log('[DailyForm] Form element found:', form);

    // Mark as initialized FIRST to prevent double-init during setup
    form.dataset.initialized = 'true';

    const captureBtn = document.getElementById('captureBtn');
    const uploadBtn = document.getElementById('uploadBtn');
    const fileInput = document.getElementById('fileInput');
    const imagePreview = document.getElementById('imagePreview');
    const cameraModalEl = document.getElementById('cameraModal');
    const camera = document.getElementById('camera');
    const canvas = document.getElementById('canvas');
    const snapBtn = document.getElementById('snapBtn');
    const dateInput = document.getElementById('date');
    const successMessage = document.getElementById('successMessage');
    const errorMessage = document.getElementById('errorMessage');
    const submitBtn = document.getElementById('submitBtn');
    const modalCloseBtn = cameraModalEl ? cameraModalEl.querySelector('[data-bs-dismiss="modal"]') : null;

    let stream = null;
    let images = [];
    let receipts = [];
    let timesheets = [];

    // Simple modal show/hide functions (works without Bootstrap)
    function showModal(modalElement) {
        if (modalElement) {
            modalElement.style.display = 'block';
            modalElement.classList.add('show');
            document.body.classList.add('modal-open');

            // Add backdrop
            const backdrop = document.createElement('div');
            backdrop.className = 'modal-backdrop fade show';
            backdrop.id = 'cameraModalBackdrop';
            document.body.appendChild(backdrop);
        }
    }

    function hideModal(modalElement) {
        if (modalElement) {
            modalElement.style.display = 'none';
            modalElement.classList.remove('show');
            document.body.classList.remove('modal-open');

            // Remove backdrop
            const backdrop = document.getElementById('cameraModalBackdrop');
            if (backdrop) {
                backdrop.remove();
            }
        }
    }

    const today = new Date();
    const year = today.getFullYear();
    const month = String(today.getMonth() + 1).padStart(2, '0');
    const day = String(today.getDate()).padStart(2, '0');
    dateInput.value = `${year}-${month}-${day}`;

    uploadBtn.addEventListener('click', () => fileInput.click());

    fileInput.addEventListener('change', function(e) {
        handleFiles(e.target.files);
    });

    // Receipt upload handling
    const uploadReceiptBtn = document.getElementById('uploadReceiptBtn');
    const receiptInput = document.getElementById('receiptInput');
    const receiptPreview = document.getElementById('receiptPreview');

    if (uploadReceiptBtn) {
        uploadReceiptBtn.addEventListener('click', () => receiptInput.click());
    }

    if (receiptInput) {
        receiptInput.addEventListener('change', function(e) {
            handleReceipts(e.target.files);
        });
    }

    // Timesheet upload handling
    const uploadTimesheetBtn = document.getElementById('uploadTimesheetBtn');
    const timesheetInput = document.getElementById('timesheetInput');
    const timesheetPreview = document.getElementById('timesheetPreview');

    if (uploadTimesheetBtn) {
        uploadTimesheetBtn.addEventListener('click', () => timesheetInput.click());
    }

    if (timesheetInput) {
        timesheetInput.addEventListener('change', function(e) {
            handleTimesheets(e.target.files);
        });
    }

    captureBtn.addEventListener('click', async function() {
        console.log('[DailyForm] Camera button clicked');
        try {
            if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
                alert('Camera access is not available. Please use HTTPS or localhost, or use the Upload Photos option instead.');
                return;
            }

            console.log('[DailyForm] Requesting camera access...');
            stream = await navigator.mediaDevices.getUserMedia({
                video: {
                    facingMode: { ideal: 'environment' },
                    width: { ideal: 1920 },
                    height: { ideal: 1080 }
                }
            });

            console.log('[DailyForm] Camera access granted!');
            camera.srcObject = stream;
            showModal(cameraModalEl);
        } catch (err) {
            console.error('[DailyForm] Camera error:', err);
            let errorMsg = 'Cannot access camera. ';
            if (err.name === 'NotAllowedError') {
                errorMsg += 'Permission denied. Please allow camera access in your browser settings.';
            } else if (err.name === 'NotFoundError') {
                errorMsg += 'No camera found on this device.';
            } else if (err.name === 'NotSupportedError') {
                errorMsg += 'Camera requires HTTPS connection. Please use the Upload Photos option instead.';
            } else {
                errorMsg += err.message + '\n\nTip: Camera requires HTTPS. Use Upload Photos as alternative.';
            }
            alert(errorMsg);
        }
    });

    // Handle modal close button
    if (modalCloseBtn) {
        modalCloseBtn.addEventListener('click', function() {
            if (stream) {
                stream.getTracks().forEach(track => track.stop());
                stream = null;
            }
            hideModal(cameraModalEl);
        });
    }

    // Handle backdrop click to close
    document.addEventListener('click', function(e) {
        if (e.target && e.target.id === 'cameraModalBackdrop') {
            if (stream) {
                stream.getTracks().forEach(track => track.stop());
                stream = null;
            }
            hideModal(cameraModalEl);
        }
    });

    snapBtn.addEventListener('click', function() {
        canvas.width = camera.videoWidth;
        canvas.height = camera.videoHeight;
        canvas.getContext('2d').drawImage(camera, 0, 0);

        canvas.toBlob(function(blob) {
            if (blob.size > 10 * 1024 * 1024) {
                alert('Image size exceeds 10MB. Please try again with lower quality.');
                return;
            }

            const reader = new FileReader();
            reader.onloadend = function() {
                addImagePreview(reader.result, `Photo ${images.length + 1}`);
            };
            reader.readAsDataURL(blob);
        }, 'image/jpeg', 0.8);

        hideModal(cameraModalEl);
    });

    function handleFiles(files) {
        Array.from(files).forEach(file => {
            if (!file.type.startsWith('image/')) {
                alert('Please select only image files.');
                return;
            }

            if (file.size > 10 * 1024 * 1024) {
                alert(`${file.name} exceeds 10MB and will be skipped.`);
                return;
            }

            const reader = new FileReader();
            reader.onload = function(e) {
                addImagePreview(e.target.result, file.name);
            };
            reader.readAsDataURL(file);
        });
        fileInput.value = '';
    }

    function addImagePreview(dataUrl, name) {
        const imageId = Date.now() + Math.random();
        images.push({ id: imageId, data: dataUrl, name: name });

        const col = document.createElement('div');
        col.className = 'col-md-4 col-6 mb-3';
        col.innerHTML = `
            <div class="card">
                <img src="${dataUrl}" class="card-img-top" style="height: 150px; object-fit: cover;">
                <div class="card-body p-2">
                    <input type="text" class="form-control form-control-sm image-name"
                           value="${name}" data-id="${imageId}" placeholder="Image description">
                    <button type="button" class="btn btn-danger btn-sm w-100 mt-2 remove-image"
                            data-id="${imageId}">
                        <i class="fa fa-trash"></i> Remove
                    </button>
                </div>
            </div>
        `;
        imagePreview.appendChild(col);

        col.querySelector('.remove-image').addEventListener('click', function() {
            images = images.filter(img => img.id != this.dataset.id);
            col.remove();
        });

        col.querySelector('.image-name').addEventListener('input', function() {
            const image = images.find(img => img.id == this.dataset.id);
            if (image) {
                image.name = this.value;
            }
        });
    }

    function handleReceipts(files) {
        Array.from(files).forEach(file => {
            if (!file.type.startsWith('image/')) {
                alert('Please select only image files for receipts.');
                return;
            }

            if (file.size > 10 * 1024 * 1024) {
                alert(`${file.name} exceeds 10MB and will be skipped.`);
                return;
            }

            const reader = new FileReader();
            reader.onload = function(e) {
                addReceiptPreview(e.target.result, file.name);
            };
            reader.readAsDataURL(file);
        });
        receiptInput.value = '';
    }

    function addReceiptPreview(dataUrl, name) {
        const receiptId = Date.now() + Math.random();
        receipts.push({ id: receiptId, data: dataUrl, name: name });

        const col = document.createElement('div');
        col.className = 'col-md-4 col-6 mb-3';
        col.innerHTML = `
            <div class="card border-success">
                <img src="${dataUrl}" class="card-img-top" style="height: 150px; object-fit: cover;">
                <div class="card-body p-2">
                    <input type="text" class="form-control form-control-sm receipt-name"
                           value="${name}" data-id="${receiptId}" placeholder="Receipt description">
                    <button type="button" class="btn btn-danger btn-sm w-100 mt-2 remove-receipt"
                            data-id="${receiptId}">
                        <i class="fa fa-trash"></i> Remove
                    </button>
                </div>
            </div>
        `;
        receiptPreview.appendChild(col);

        col.querySelector('.remove-receipt').addEventListener('click', function() {
            receipts = receipts.filter(r => r.id != this.dataset.id);
            col.remove();
        });

        col.querySelector('.receipt-name').addEventListener('input', function() {
            const receipt = receipts.find(r => r.id == this.dataset.id);
            if (receipt) {
                receipt.name = this.value;
            }
        });
    }

    function handleTimesheets(files) {
        Array.from(files).forEach(file => {
            const validTypes = ['image/', 'application/pdf', 'application/vnd.ms-excel',
                              'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
                              'application/msword', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'];

            const isValid = validTypes.some(type => file.type.startsWith(type) || file.type === type);

            if (!isValid) {
                alert(`${file.name} is not a supported file type.`);
                return;
            }

            if (file.size > 10 * 1024 * 1024) {
                alert(`${file.name} exceeds 10MB and will be skipped.`);
                return;
            }

            const reader = new FileReader();
            reader.onload = function(e) {
                addTimesheetPreview(e.target.result, file.name, file.type);
            };
            reader.readAsDataURL(file);
        });
        timesheetInput.value = '';
    }

    function addTimesheetPreview(dataUrl, name, fileType) {
        const tsId = Date.now() + Math.random();
        timesheets.push({ id: tsId, data: dataUrl, name: name });

        const col = document.createElement('div');
        col.className = 'col-md-6 mb-3';

        let icon = 'fa-file';
        if (fileType.startsWith('image/')) icon = 'fa-file-image';
        else if (fileType.includes('pdf')) icon = 'fa-file-pdf';
        else if (fileType.includes('excel') || fileType.includes('spreadsheet')) icon = 'fa-file-excel';
        else if (fileType.includes('word') || fileType.includes('document')) icon = 'fa-file-word';

        col.innerHTML = `
            <div class="card border-info">
                <div class="card-body p-2">
                    <div class="d-flex align-items-center">
                        <i class="fa ${icon} fa-3x text-info me-3"></i>
                        <div class="flex-grow-1">
                            <input type="text" class="form-control form-control-sm timesheet-name"
                                   value="${name}" data-id="${tsId}" placeholder="Timesheet description">
                        </div>
                    </div>
                    <button type="button" class="btn btn-danger btn-sm w-100 mt-2 remove-timesheet"
                            data-id="${tsId}">
                        <i class="fa fa-trash"></i> Remove
                    </button>
                </div>
            </div>
        `;
        timesheetPreview.appendChild(col);

        col.querySelector('.remove-timesheet').addEventListener('click', function() {
            timesheets = timesheets.filter(ts => ts.id != this.dataset.id);
            col.remove();
        });

        col.querySelector('.timesheet-name').addEventListener('input', function() {
            const timesheet = timesheets.find(ts => ts.id == this.dataset.id);
            if (timesheet) {
                timesheet.name = this.value;
            }
        });
    }

    form.addEventListener('submit', async function(e) {
        e.preventDefault();

        // Validate photos if checkbox is checked
        const photosExist = document.getElementById('photos_exist').checked;
        if (photosExist && images.length === 0) {
            errorMessage.classList.remove('d-none');
            successMessage.classList.add('d-none');
            document.getElementById('errorText').textContent = 'Photos are required. Please upload at least one photo.';
            return;
        }

        // Validate receipts if checkbox is checked
        const receiptsExist = document.getElementById('receipts_exist').checked;
        if (receiptsExist && receipts.length === 0) {
            errorMessage.classList.remove('d-none');
            successMessage.classList.add('d-none');
            document.getElementById('errorText').textContent = 'Receipts are required. Please upload at least one receipt.';
            return;
        }

        const formData = {
            project_id: document.getElementById('project_id').value,
            employee_id: document.getElementById('employee_id').value,
            date: document.getElementById('date').value,
            description: document.getElementById('description').value,
            time_in: document.getElementById('time_in').value,
            time_out: document.getElementById('time_out').value,
            lunch_time: document.getElementById('lunch_time').value,
            techs_on_site: document.getElementById('techs_on_site').value,
            materials_used: document.getElementById('materials_used').value,
            issues: document.getElementById('issues').value,
            location: document.getElementById('location').value,
            weather: document.getElementById('weather').value,
            images: images,
            receipts: receipts,
            timesheets: timesheets,
        };

        submitBtn.disabled = true;
        submitBtn.innerHTML = '<span class="spinner-border spinner-border-sm me-2"></span>Submitting...';

        try {
            const response = await fetch('/project/daily/submit', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    jsonrpc: '2.0',
                    method: 'call',
                    params: formData,
                }),
            });

            const result = await response.json();
            console.log('Submit response:', result);

            if (result.result && result.result.success) {
                successMessage.classList.remove('d-none');
                errorMessage.classList.add('d-none');
                document.getElementById('successText').textContent =
                    `${result.result.message} (${result.result.daily_name}) - ID: ${result.result.daily_id}`;

                form.reset();
                const today = new Date();
                const year = today.getFullYear();
                const month = String(today.getMonth() + 1).padStart(2, '0');
                const day = String(today.getDate()).padStart(2, '0');
                dateInput.value = `${year}-${month}-${day}`;
                images = [];
                receipts = [];
                timesheets = [];
                imagePreview.innerHTML = '';
                receiptPreview.innerHTML = '';
                timesheetPreview.innerHTML = '';

                setTimeout(() => {
                    successMessage.classList.add('d-none');
                }, 5000);
            } else {
                throw new Error(result.result?.message || result.error?.message || 'Submission failed');
            }
        } catch (error) {
            errorMessage.classList.remove('d-none');
            successMessage.classList.add('d-none');
            document.getElementById('errorText').textContent = error.message;
        } finally {
            submitBtn.disabled = false;
            submitBtn.innerHTML = '<i class="fa fa-check"></i> Submit Daily Report';
        }
    });
}

// Call init function when DOM is ready
if (document.readyState === 'loading') {
    console.log('[DailyForm] DOM still loading, waiting for DOMContentLoaded...');
    document.addEventListener('DOMContentLoaded', initDailyForm);
} else {
    console.log('[DailyForm] DOM already loaded, initializing immediately...');
    initDailyForm();
}

