// Handle project autocomplete with visible dropdown
const projectSearchInput = document.getElementById('project_id_search');
const projectIdInput = document.getElementById('project_id');
const projectDropdown = document.getElementById('project_dropdown');
const projectsDataEl = document.getElementById('projects_data');

if (projectSearchInput && projectIdInput && projectDropdown && projectsDataEl) {
    let projectsData = [];
    try {
        projectsData = JSON.parse(projectsDataEl.textContent);
    } catch (e) {
        console.error('Failed to parse projects data:', e);
    }

    function showDropdown(filteredProjects) {
        projectDropdown.innerHTML = '';

        if (filteredProjects.length === 0) {
            projectDropdown.style.display = 'none';
            return;
        }

        filteredProjects.forEach(project => {
            const item = document.createElement('a');
            item.href = '#';
            item.className = 'list-group-item list-group-item-action';
            item.textContent = project.name;
            item.dataset.id = project.id;
            item.dataset.name = project.name;

            item.addEventListener('click', function(e) {
                e.preventDefault();
                projectSearchInput.value = this.dataset.name;
                projectIdInput.value = this.dataset.id;
                projectDropdown.style.display = 'none';
            });

            projectDropdown.appendChild(item);
        });

        projectDropdown.style.display = 'block';
    }

    function filterProjects(searchTerm) {
        const term = searchTerm.toLowerCase();
        return projectsData.filter(project =>
            project.name.toLowerCase().includes(term)
        );
    }

    // Show all projects on focus
    projectSearchInput.addEventListener('focus', function() {
        const filtered = filterProjects(this.value || '');
        showDropdown(filtered);
    });

    // Filter as user types
    projectSearchInput.addEventListener('input', function() {
        const filtered = filterProjects(this.value);
        showDropdown(filtered);

        // Clear hidden field if input doesn't match any project exactly
        const exactMatch = projectsData.find(p => p.name === this.value);
        projectIdInput.value = exactMatch ? exactMatch.id : '';
    });

    // Hide dropdown when clicking outside
    document.addEventListener('click', function(e) {
        if (!projectSearchInput.contains(e.target) && !projectDropdown.contains(e.target)) {
            projectDropdown.style.display = 'none';
        }
    });

    // Clear hidden field when search input is cleared
    projectSearchInput.addEventListener('change', function() {
        if (!this.value) {
            projectIdInput.value = '';
        }
    });
}

