.daily-form-container {
    max-width: 900px;
    margin: 0 auto;
}

#camera {
    width: 100%;
    max-width: 640px;
    border: 2px solid #ddd;
    border-radius: 8px;
}

#imagePreview .card {
    border: 1px solid #ddd;
    border-radius: 8px;
    overflow: hidden;
}

#imagePreview .card img {
    border-bottom: 1px solid #ddd;
}

.image-name {
    font-size: 0.875rem;
}

.remove-image {
    font-size: 0.875rem;
}

@media (max-width: 768px) {
    #imagePreview .col-6 {
        padding-left: 5px;
        padding-right: 5px;
    }
}

.btn-primary {
    background-color: #0d6efd;
    border-color: #0d6efd;
}

.btn-success {
    background-color: #198754;
    border-color: #198754;
}

.btn-danger {
    background-color: #dc3545;
    border-color: #dc3545;
}

.spinner-border-sm {
    width: 1rem;
    height: 1rem;
    border-width: 0.15em;
}

/* Modal display styles (works without Bootstrap JS) */
#cameraModal {
    display: none;
    position: fixed;
    z-index: 1050;
    left: 0;
    top: 0;
    width: 100%;
    height: 100%;
    overflow: auto;
}

#cameraModal.show {
    display: block !important;
}

.modal-backdrop {
    position: fixed;
    top: 0;
    left: 0;
    z-index: 1040;
    width: 100vw;
    height: 100vh;
    background-color: #000;
}

.modal-backdrop.fade {
    opacity: 0;
}

.modal-backdrop.show {
    opacity: 0.5;
}

body.modal-open {
    overflow: hidden;
}

#camera {
    max-width: 100%;
    height: auto;
}

